web_EditPage.populateForm = function(cfg) {
	var form = web_EditPage.query(web_EditPage.container,".edit-form");
	if(form == null) {
		return;
	}
	var fields = web_EditPage.queryAll(form,".form-field");
	if(fields.length < 7) {
		return;
	}
	var nameInput = web_EditPage.input("text",null,cfg.name,"form-input",fields[0]);
	var passInput = web_EditPage.input("password",null,cfg.password != null ? cfg.password : "","form-input",fields[1]);
	var maxInput = web_EditPage.input("number",null,Std.string(cfg.maxPlayers),"form-input",fields[2]);
	maxInput.setAttribute("min","1");
	maxInput.setAttribute("max","100");
	var autoInput = web_EditPage.input("number",null,Std.string(cfg.autosaveInterval),"form-input",fields[3]);
	autoInput.setAttribute("min","1");
	autoInput.setAttribute("max","60");
	var slotsInput = web_EditPage.input("number",null,Std.string(cfg.autosaveSlots),"form-input",fields[4]);
	slotsInput.setAttribute("min","1");
	slotsInput.setAttribute("max","20");
	var saveField = fields[5];
	web_EditPage.clear(saveField);
	web_EditPage.label("Save File","field-label",saveField);
	var saveRow = web_EditPage.div("save-field-row",saveField);
	var saveText = window.document.createElement("input");
	saveText.type = "text";
	saveText.value = cfg.saveFile != null ? cfg.saveFile : "";
	saveText.className = "form-input save-file-input";
	saveText.placeholder = "Select or enter save file";
	saveRow.appendChild(saveText);
	var filePicker = window.document.createElement("input");
	filePicker.type = "file";
	filePicker.accept = ".zip,.factorio";
	filePicker.className = "save-file-picker";
	saveRow.appendChild(filePicker);
	var uploadBtn = window.document.createElement("button");
	uploadBtn.textContent = "Upload";
	uploadBtn.className = "btn btn-upload-save";
	saveRow.appendChild(uploadBtn);
	uploadBtn.addEventListener("click",function(_) {
		filePicker.click();
		return false;
	});
	filePicker.addEventListener("change",function(_) {
		var files = filePicker.files;
		if(files == null || files.length == 0) {
			return;
		}
		var file = files.item(0);
		if(file == null) {
			return;
		}
		uploadBtn.disabled = true;
		uploadBtn.textContent = "Uploading...";
		web_Api.uploadSaveFile(web_EditPage.serverId,file,function(data) {
			var uploadedName = data.saveFile != null ? data.saveFile : file.name;
			saveText.value = uploadedName;
			uploadBtn.disabled = false;
			uploadBtn.textContent = "Upload";
			web_EditPage.toast("Uploaded: " + uploadedName,false);
		},function(err) {
			uploadBtn.disabled = false;
			uploadBtn.textContent = "Upload";
			web_EditPage.toast("Upload failed: " + err,true);
		});
	});
	var verSelect = web_EditPage.query(fields[6],"select");
	if(verSelect != null) {
		web_EditPage.selectedVersion = cfg.version != null ? cfg.version : "latest";
	}
	var adminsInput = web_EditPage.input("text",null,"","form-input",fields[7]);
	if(cfg.admins != null) {
		adminsInput.value = cfg.admins.join(", ");
	}
	web_EditPage.populateMods(cfg.mods);
};
web_EditPage.populateMods = function(mods) {
	if(web_EditPage.modListContainer == null) {
		return;
	}
	web_EditPage.clear(web_EditPage.modListContainer);
	if(mods == null || mods.length == 0) {
		web_EditPage.spn("No mods loaded","mod-empty-msg",web_EditPage.modListContainer);
		return;
	}
	web_EditPage.renderModList(mods);
};
web_EditPage.renderModList = function(mods) {
	web_EditPage.clear(web_EditPage.modListContainer);
	var _g = 0;
	while(_g < mods.length) {
		var mod = [mods[_g]];
		++_g;
		var row = web_EditPage.div("mod-row",web_EditPage.modListContainer);
		var checkBox = window.document.createElement("input");
		checkBox.type = "checkbox";
		checkBox.checked = mod[0].enabled;
		checkBox.className = "mod-checkbox";
		checkBox.addEventListener("change",(function(mod) {
			return function(e) {
				var target = e.target;
				var _g = 0;
				while(_g < mods.length) {
					var m = mods[_g];
					++_g;
					if(m.name == mod[0].name) {
						m.enabled = target.checked;
						break;
					}
				}
				web_Api.toggleMod(web_EditPage.serverId,mod[0].name,null,(function() {
					return function(err) {
						web_EditPage.toast("Failed to toggle mod: " + err,true);
					};
				})());
			};
		})(mod));
		row.appendChild(checkBox);
		var modInfo = web_EditPage.div("mod-info",row);
		var modTitle = web_EditPage.spn(mod[0].title != null ? mod[0].title : mod[0].name,"mod-title",modInfo);
		var modName = web_EditPage.spn(mod[0].name,"mod-name",modInfo);
		var modVersion = null;
		if(mod[0].version != null && mod[0].version != "") {
			modVersion = web_EditPage.spn("(v" + Std.string(mod[0].version) + ")","mod-version",modInfo);
		}
		web_EditPage.btn("Remove","btn btn-mod-remove",row,(function(mod) {
			return function() {
				web_EditPage.doRemoveMod(mod[0].name);
			};
		})(mod));
	}
};
web_EditPage.doSearchAndAdd = function() {
	var searchText = StringTools.trim(web_EditPage.modSearchInput.value);
	if(searchText == "") {
		web_EditPage.toast("Enter a mod name to search",true);
		return;
	}
	web_Api.searchMods(searchText,function(data) {
		var results = data;
		if(results == null || results.length == 0) {
			web_EditPage.toast("No mods found for: " + searchText,true);
			return;
		}
		var first = results[0];
		var modName = first.name != null ? first.name : first.id != null ? first.id : searchText;
		var modTitle = first.title != null ? first.title : modName;
		var modVersion = first.version != null ? first.version : "";
		web_Api.addMod(web_EditPage.serverId,modName,modTitle,modVersion,function(_) {
			web_EditPage.toast("Added mod: " + modTitle,false);
			web_EditPage.loadServerConfig();
		},function(err) {
			web_EditPage.toast("Failed to add mod: " + err,true);
		});
	},function(err) {
		web_EditPage.toast("Search failed: " + err,true);
	});
};
