web_EditPage.queryAll = function(parent,selector) {
	var nodeList = parent.querySelectorAll(selector);
	var arr = [];
	var len = nodeList.length;
	var _g = 0;
	var _g1 = len;
	while(_g < _g1) {
		var i = _g++;
		arr.push(nodeList.item(i));
	}
	return arr;
};
